import React from 'react';
import '../styles/ResourceManagement.css';

function MarketInfo() {
  return (
    <div className="market-info">
      <h1>Market Information</h1>
      <p>Current market prices and demand forecasts.</p>
    </div>
  );
}

export default MarketInfo;
